const item = $input.first().json;
return [{ json: {
  user_id: item.user_id || '',
  conversation_id: item.conversation_id || '',
  role: item.role || 'end_user',
  message: item.message || '',
  has_image: item.has_image || false,
  image_url: item.image_url || null,
  image_mime_type: item.image_mime_type || null,
  sent_at: item.sent_at || new Date().toISOString(),
  prescription_data: {
    is_prescription: false,
    medications: [],
    doctor_name: null,
    clinic_name: null,
    diagnosis: null,
    raw_ocr: ''
  }
}}];

// ── User Resolver ─────────────────────────────────────────────────────────
// Determines role-based collection without $env (blocked in task runner).
// The AI agent uses native MongoDB tools for actual user data lookups.
const mergedData = $input.first().json;
const userId = mergedData.user_id || '';
const role   = mergedData.role    || 'end_user';

let collection = 'users';
if (role === 'pharmacy' || role === 'pharmacy_owner') collection = 'pharmacies';
else if (role === 'admin' || role === 'super_admin' || role === 'moderator') collection = 'admins';

// userDoc is empty here — the AI agent will query MongoDB directly via tools
return [{ json: {
  ...mergedData,
  userDoc: {},
  resolvedCollection: collection,
  resolvedRole: role
}}];

const raw = $('AI Agent').first().json.output || '';

const plain = raw
  // Headers: ### Title → Title
  .replace(/^#{1,6}\s+/gm, '')
  // Bold/Italic: ***text***, **text**, *text*, __text__, _text_
  .replace(/\*{1,3}([^*]+)\*{1,3}/g, '$1')
  .replace(/_{1,2}([^_]+)_{1,2}/g, '$1')
  // Inline code: `code`
  .replace(/`([^`]+)`/g, '$1')
  // Code blocks: ```...```
  .replace(/```[\s\S]*?```/g, '')
  // Blockquotes: > text
  .replace(/^>\s+/gm, '')
  // Horizontal rules
  .replace(/^[-*_]{3,}\s*$/gm, '')
  // Links: [text](url) → text
  .replace(/\[([^\]]+)\]\([^)]+\)/g, '$1')
  // Images: ![alt](url) → alt
  .replace(/!\[([^\]]*)\]\([^)]+\)/g, '$1')
  // Unordered list bullets: - item, * item, • item → item
  .replace(/^[\s]*[-*•]\s+/gm, '')
  // Ordered list numbers: 1. item → item
  .replace(/^[\s]*\d+\.\s+/gm, '')
  // Tables: strip | separators and alignment rows
  .replace(/^\|(.+)\|$/gm, (_, inner) =>
    inner.split('|').map(c => c.trim()).filter(c => !/^[-:]+$/.test(c)).join('  ')
  )
  .replace(/^[\s|:-]+$/gm, '')
  // Collapse 3+ newlines to 2
  .replace(/\n{3,}/g, '\n\n')
  .trim();

return [{ json: { ...$input.first().json, ai_output_clean: plain } }];
